@* Displays a single task with priority badge and move buttons *@

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1 text-muted small">@Task.Assignee</p>
        <div class="d-flex justify-content-between align-items-center">
            <div>
                <span class="badge @PriorityClass">@Task.Priority</span>
                <span class="text-muted small ms-1">@Task.DueDate.ToString("MMM dd")</span>
            </div>
            <div>
                @if (ShowMoveLeft)
                {
                    <button class="btn btn-sm btn-outline-secondary py-0 px-1 me-1"
                            @onclick="OnMoveLeft"
                            title="Move left">◀</button>
                }
                @if (ShowMoveRight)
                {
                    <button class="btn btn-sm btn-outline-secondary py-0 px-1"
                            @onclick="OnMoveRight"
                            title="Move right">▶</button>
                }
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback OnMoveLeft { get; set; }
    [Parameter] public EventCallback OnMoveRight { get; set; }

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };
}

@* Inline form to create a new task within a column *@

<div class="card mb-2 border-primary">
    <div class="card-body p-2">
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Title"
                   @bind="title" />
        </div>
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Assignee"
                   @bind="assignee" />
        </div>
        <div class="mb-2">
            <select class="form-select form-select-sm" @bind="priority">
                <option value="High">High</option>
                <option value="Medium">Medium</option>
                <option value="Low">Low</option>
            </select>
        </div>
        <div class="mb-2">
            <input type="date" class="form-control form-control-sm" @bind="dueDate" />
        </div>
        <div class="d-flex gap-1">
            <button class="btn btn-sm btn-primary" @onclick="HandleSave" disabled="@saving">
                @(saving ? "Saving…" : "Save")
            </button>
            <button class="btn btn-sm btn-outline-secondary" @onclick="HandleCancel" disabled="@saving">
                Cancel
            </button>
        </div>
        @if (!string.IsNullOrEmpty(error))
        {
            <div class="text-danger small mt-1">@error</div>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string DefaultStatus { get; set; } = "";
    [Parameter] public EventCallback<TaskItem> OnSave { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private string title = "";
    private string assignee = "";
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool saving;
    private string? error;

    private async Task HandleSave()
    {
        if (string.IsNullOrWhiteSpace(title))
        {
            error = "Title is required.";
            return;
        }

        saving = true;
        error = null;
        try
        {
            await OnSave.InvokeAsync(new TaskItem(0, title.Trim(), assignee.Trim(), priority, dueDate, DefaultStatus));
        }
        catch (Exception ex)
        {
            error = ex.Message;
        }
        finally
        {
            saving = false;
        }
    }

    private async Task HandleCancel() => await OnCancel.InvokeAsync();
}

@* A single Kanban column: header with count, task cards, and add-task toggle *@

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>@ColumnName</strong>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body p-2 overflow-auto" style="max-height: 60vh;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          ShowMoveLeft="ShowMoveLeft"
                          ShowMoveRight="ShowMoveRight"
                          OnMoveLeft="() => HandleMoveLeft(task)"
                          OnMoveRight="() => HandleMoveRight(task)" />
            }

            @if (showForm)
            {
                <AddTaskForm DefaultStatus="@ColumnName"
                             OnSave="HandleTaskCreated"
                             OnCancel="() => showForm = false" />
            }
        </div>
        <div class="card-footer p-2">
            <button class="btn btn-sm btn-outline-primary w-100" @onclick="() => showForm = true"
                    disabled="@showForm">
                + Add Task
            </button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = "";
    [Parameter] public List<TaskItem> Tasks { get; set; } = [];
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback<(TaskItem Task, string Direction)> OnMove { get; set; }
    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }

    private bool showForm;

    private async Task HandleMoveLeft(TaskItem task) =>
        await OnMove.InvokeAsync((task, "left"));

    private async Task HandleMoveRight(TaskItem task) =>
        await OnMove.InvokeAsync((task, "right"));

    private async Task HandleTaskCreated(TaskItem task)
    {
        await OnTaskCreated.InvokeAsync(task);
        showForm = false;
    }
}

@* Client-side search bar for filtering tasks by title *@

<div class="mb-3">
    <input type="text" class="form-control" placeholder="Search tasks by title…"
           value="@SearchTerm"
           @oninput="HandleInput" />
</div>

@code {
    [Parameter] public string SearchTerm { get; set; } = "";
    [Parameter] public EventCallback<string> SearchTermChanged { get; set; }

    private async Task HandleInput(ChangeEventArgs e)
    {
        var value = e.Value?.ToString() ?? "";
        await SearchTermChanged.InvokeAsync(value);
    }
}

@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (loading)
{
    <div class="text-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading…</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-sm btn-outline-danger ms-2" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStats Tasks="tasks" />

    <BoardSearchBar SearchTerm="@searchTerm" SearchTermChanged="v => searchTerm = v" />

    <div class="row g-3">
        @for (int i = 0; i < columns.Length; i++)
        {
            var columnIndex = i;
            var columnName = columns[columnIndex];
            <KanbanColumn ColumnName="@columnName"
                          Tasks="GetFilteredTasks(columnName)"
                          ShowMoveLeft="columnIndex > 0"
                          ShowMoveRight="columnIndex < columns.Length - 1"
                          OnMove="e => HandleMove(e.Task, e.Direction, columnIndex)"
                          OnTaskCreated="HandleTaskCreated" />
        }
    </div>
}

@code {
    private static readonly string[] columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> tasks = [];
    private string searchTerm = "";
    private bool loading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync() => await LoadTasks();

    private async Task LoadTasks()
    {
        loading = true;
        errorMessage = null;
        try
        {
            tasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            loading = false;
        }
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var filtered = tasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            filtered = filtered.Where(t => t.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));
        }
        return filtered.ToList();
    }

    private async Task HandleMove(TaskItem task, string direction, int currentColumnIndex)
    {
        var targetIndex = direction == "left" ? currentColumnIndex - 1 : currentColumnIndex + 1;
        if (targetIndex < 0 || targetIndex >= columns.Length) return;

        var newStatus = columns[targetIndex];
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            var index = tasks.FindIndex(t => t.Id == task.Id);
            if (index >= 0)
            {
                tasks[index] = task with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task HandleTaskCreated(TaskItem formData)
    {
        var created = await TaskService.CreateTaskAsync(formData.Title, formData.Assignee, formData.Priority, formData.DueDate);
        tasks.Add(created);
    }
}

