toolArgs.file_text:
@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (loading)
{
    <div class="text-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading…</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-sm btn-outline-danger ms-2" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStats Tasks="tasks" />

    <BoardSearchBar SearchTerm="@searchTerm" SearchTermChanged="v => searchTerm = v" />

    <div class="row g-3">
        @for (int i = 0; i < columns.Length; i++)
        {
            var columnIndex = i;
            var columnName = columns[columnIndex];
            <KanbanColumn ColumnName="@columnName"
                          Tasks="GetFilteredTasks(columnName)"
                          ShowMoveLeft="columnIndex > 0"
                          ShowMoveRight="columnIndex < columns.Length - 1"
                          OnMove="e => HandleMove(e.Task, e.Direction, columnIndex)"
                          OnTaskCreated="HandleTaskCreated" />
        }
    </div>
}

@code {
    private static readonly string[] columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> tasks = [];
    private string searchTerm = "";
    private bool loading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync() => await LoadTasks();

    private async Task LoadTasks()
    {
        loading = true;
        errorMessage = null;
        try
        {
            tasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            loading = false;
        }
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var filtered = tasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            filtered = filtered.Where(t => t.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));
        }
        return filtered.ToList();
    }

    private async Task HandleMove(TaskItem task, string direction, int currentColumnIndex)
    {
        var targetIndex = direction == "left" ? currentColumnIndex - 1 : currentColumnIndex + 1;
        if (targetIndex < 0 || targetIndex >= columns.Length) return;

        var newStatus = columns[targetIndex];
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            var index = tasks.FindIndex(t => t.Id == task.Id);
            if (index >= 0)
            {
                tasks[index] = task with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task HandleTaskCreated(TaskItem formData)
    {
        var created = await TaskService.CreateTaskAsync(formData.Title, formData.Assignee, formData.Priority, formData.DueDate);
        tasks.Add(created);
    }
}

